func solve(nums []int64, queries [][]int64) []int64 {
    ans := make([]int64, len(queries))
    for _, q := range queries {
        l := q[0]
        r := q[1]
        t := q[2]
        freq := make(map[int64]int64)
        for i := l; i <= r; i++ {
            num := nums[i]
            freq[num]++
        }
        maxFreq := int64(-1)
        bestNum := int64(-1)
        for num, cnt := range freq {
            if cnt >= t {
                if cnt > maxFreq || (cnt == maxFreq && num < bestNum) {
                    maxFreq = cnt
                    bestNum = num
                }
            }
        }
        ans = append(ans, bestNum)
    }
    return ans
}
